INSERT INTO data_report (
    report_name, report_type, start_date, end_date, status, created_at, tenant_id
) VALUES (
             #{reportName}, #{reportType}, #{startDate}, #{endDate}, #{status}, NOW(), #{tenantId}
         )

mapper.select:
SELECT *
FROM data_report



        AND tenant_id = #{tenantId}



        AND report_type = #{reportType}


        AND start_date >= #{startDate}


        AND end_date <= #{endDate}


        AND report_name LIKE CONCAT('%', #{reportName}, '%')



ORDER BY created_at DESC
